const BATCH_BY_NUM = { 3: BATCH_3, 4: BATCH_4, 5: BATCH_5, 6: BATCH_6 };
const AUTHOR_SLOT_BY_NUM = { 3: 1, 4: 2, 5: 1, 6: 1 };
const SUFFIX_BY_NUM = { 3: 'batch3', 4: 'batch4', 5: 'batch5', 6: 'batch6' };
const LIKE_COUNT_BY_NUM = { 5: 18, 6: 21 };

const POSTS = BATCH_BY_NUM[batchNum];
const authorSlot = AUTHOR_SLOT_BY_NUM[batchNum];
const suffix = SUFFIX_BY_NUM[batchNum];

function buildPost([lang, title, body, comments, tagBase], seed) {
  const { authorIndex, commentIndices } = assignSeedAuthors(lang, comments.length, authorSlot);
  const likeCount = LIKE_COUNT_BY_NUM[batchNum] ?? 18 + (seed % 27);
  return {
    title,
    body,
    authorIndex,
    language: lang,
    tags: [...tagBase, 'question', lang],
    comments: comments.map((c, i) => ({
      body: c,
      authorIndex: commentIndices[i],
    })),
    likeCount,
  };
}

const out = POSTS.map((p, i) => buildPost(p, i));
const outPath = path.join(root, `public/data/community_seed_all_languages_questions_${suffix}.json`);
fs.writeFileSync(outPath, JSON.stringify(out, null, 2) + '\n');
console.log('Wrote', out.length, 'posts to', outPath);
